import asyncio, json, os, sys

async def main():
    proc = await asyncio.create_subprocess_exec(
        '.venv/bin/python', '-m', 'routed_image_gen',
        stdin=asyncio.subprocess.PIPE, stdout=asyncio.subprocess.PIPE,
        stderr=asyncio.subprocess.PIPE,
        cwd='/root/.openclaw/routed-image-gen',
        env={**os.environ, 'PYTHONPATH': 'src'}
    )

    async def read_msg(timeout=180):
        try:
            line = await asyncio.wait_for(proc.stdout.readline(), timeout)
            if not line: return None
            return json.loads(line.decode())
        except asyncio.TimeoutError:
            return None

    # Init
    init = json.dumps({'jsonrpc':'2.0','id':1,'method':'initialize','params':{'protocolVersion':'2024-11-05','capabilities':{},'clientInfo':{'name':'test','version':'1.0'}}})
    proc.stdin.write((init + '\n').encode()); await proc.stdin.drain()
    await read_msg(10)

    notif = json.dumps({'jsonrpc':'2.0','method':'notifications/initialized'})
    proc.stdin.write((notif + '\n').encode()); await proc.stdin.drain()

    tool_args = {
        'prompt': 'A stunning 20-year-old young Asian woman, radiant skin, sparkling eyes, long silky dark hair gently blowing in the breeze, wearing a simple white sundress. Natural golden-hour sunlight, soft dreamy bokeh background with pink cherry blossoms, photorealistic style, professional portrait photography, 8K quality',
        'route_mode': 'premium',
        'size': '1024x1024',
        'max_iterations': 1
    }
    req = json.dumps({'jsonrpc':'2.0','id':2,'method':'tools/call','params':{'name':'generate_image_iterative','arguments':tool_args}})
    print('>>> 开始生图（Grsai relay → GPT-Image-2）...', flush=True)
    proc.stdin.write((req + '\n').encode()); await proc.stdin.drain()

    # Image gen can take a while - wait up to 300 seconds
    result = await read_msg(300)
    if result:
        if 'result' in result:
            for c in result['result']['content']:
                if c.get('type') == 'text':
                    print(c['text'])
        elif 'error' in result:
            print('MCP ERROR:', result['error'])
    else:
        print('TIMEOUT: No response after 5 minutes')
        stderr_data = await proc.stderr.read()
        if stderr_data:
            print('STDERR:', stderr_data.decode()[-500:])

    proc.terminate(); await proc.wait()

asyncio.run(main())
