#!/usr/bin/env python3
"""MCP image generation script - proper stdio JSON-RPC handling"""
import json, subprocess, sys, os, time

SERVER_DIR = "/root/.openclaw/routed-image-gen"
ENV = {
    "PYTHONPATH": "src",
    "IMAGE_GEN_OUTPUT_DIR": f"{SERVER_DIR}/generated-images",
    "OPENAI_BASE_URL": "https://grsai.dakka.com.cn/v1/api/generate",
    "OPENAI_IMAGE_ENDPOINT": "https://grsai.dakka.com.cn/v1/api/generate",
    "PATH": f"{SERVER_DIR}/.venv/bin:/usr/bin:/bin",
}

def start_server():
    proc = subprocess.Popen(
        [f"{SERVER_DIR}/.venv/bin/python", "-m", "routed_image_gen"],
        stdin=subprocess.PIPE, stdout=subprocess.PIPE, stderr=subprocess.PIPE,
        cwd=SERVER_DIR, env=ENV,
        bufsize=0
    )
    return proc

def send_jsonrpc(proc, payload):
    line = json.dumps(payload) + "\n"
    proc.stdin.write(line.encode())
    proc.stdin.flush()

def read_response(proc, timeout=60):
    """Read one JSON line from stdout"""
    import select
    ready, _, _ = select.select([proc.stdout], [], [], timeout)
    if not ready:
        return None
    line = proc.stdout.readline()
    if not line:
        return None
    return json.loads(line.decode().strip())

def read_stderr(proc):
    import select
    ready, _, _ = select.select([proc.stderr], [], [], 0.1)
    data = b""
    while ready:
        chunk = proc.stderr.read(4096)
        if not chunk:
            break
        data += chunk
        ready, _, _ = select.select([proc.stderr], [], [], 0.1)
    return data.decode()

def main():
    products = sys.argv[1:]
    if not products:
        print("Usage: mcp_gen.py 'product_name|price' ...")
        sys.exit(1)

    proc = start_server()
    time.sleep(1)

    # Step 1: Initialize
    send_jsonrpc(proc, {
        "jsonrpc": "2.0", "id": 1, "method": "initialize",
        "params": {
            "protocolVersion": "2024-11-05",
            "capabilities": {},
            "clientInfo": {"name": "cli", "version": "1.0"}
        }
    })

    resp = read_response(proc, timeout=10)
    if resp:
        print(f"INIT: {json.dumps(resp, ensure_ascii=False)[:300]}")

    # Step 2: Send initialized notification
    send_jsonrpc(proc, {"jsonrpc": "2.0", "method": "notifications/initialized"})
    time.sleep(0.5)

    # Step 3: Generate images for each product
    for i, product in enumerate(products):
        parts = product.split("|")
        name = parts[0]
        price = parts[1] if len(parts) > 1 else ""

        prompt = f"生成一张电商大促促销图，商品：{name}，价格：{price}。风格：中国电商618/双11大促风格，红色金色为主色调，突出价格优势，画面精美专业。"

        print(f"\n🎨 [{i+1}/{len(products)}] 生成: {name} ({price})")
        print(f"   Prompt: {prompt[:80]}...")

        send_jsonrpc(proc, {
            "jsonrpc": "2.0", "id": 100 + i, "method": "tools/call",
            "params": {
                "name": "generate_image_iterative",
                "arguments": {
                    "prompt": prompt,
                    "size": "1024x1024",
                    "iterations": 1
                }
            }
        })

        # Read response - may take a while for image generation
        resp = read_response(proc, timeout=120)
        if resp:
            result = resp.get("result", {})
            content = result.get("content", [])
            for c in content:
                if c.get("type") == "text":
                    print(f"   Result: {c.get('text','')[:200]}")
                elif c.get("type") == "image":
                    print(f"   Image data received ({len(c.get('data',''))} chars)")

            # Also read any follow-up responses
            time.sleep(2)
            while True:
                r2 = read_response(proc, timeout=3)
                if r2 is None:
                    break
                result2 = r2.get("result", {})
                content2 = result2.get("content", [])
                for c in content2:
                    if c.get("type") == "text":
                        print(f"   Follow-up: {c.get('text','')[:200]}")
        else:
            print(f"   ❌ No response (timeout)")
            err = read_stderr(proc)
            if err:
                print(f"   Stderr: {err[:300]}")

    proc.terminate()
    print("\n✅ Done. Check generated-images/ for output files.")

if __name__ == "__main__":
    main()

